class Playlist:
    songs = []

    @classmethod
    def add_song(cls, title, artist, duration):
        cls.songs.append({"title": title, "artist": artist, "duration": duration})

    @classmethod
    def remove_song(cls, title):
        cls.songs = [song for song in cls.songs if song["title"] != title]

    @classmethod
    def get_total_duration(cls):
        return sum(song["duration"] for song in cls.songs)

    @classmethod
    def display_playlist(cls):
        for i, song in enumerate(cls.songs, 1):
            minutes, seconds = divmod(song["duration"], 60)
            print(f"{i}. {song['title']} by {song['artist']} - {minutes}:{seconds:02d}")

def main():
    while True:
        command = input().strip()
        if command == "exit":
            break
        elif command == "add":
            title, artist, duration = input().strip().split(';')
            Playlist.add_song(title, artist, int(duration))
        elif command == "remove":
            title = input().strip()
            Playlist.remove_song(title)
        elif command == "duration":
            print(Playlist.get_total_duration())
        elif command == "display":
            Playlist.display_playlist()

if __name__ == "__main__":
    main()
